(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"waist-hip-ratio",fields:[{"key":"waist","label":"허리둘레 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hip","label":"엉덩이둘레 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"건강 상태를 진단하는 도구가 아니며 측정 위치에 따라 결과가 달라질 수 있습니다.",compute:function(x){var w=Number(x.waist),h=Number(x.hip);if(![w,h].every(Number.isFinite)||w<=0||h<=0)return{error:"둘레는 0보다 크게 입력해 주세요."};return{ratio:w/h};},format:function(r,api){return api.resultCard("허리·엉덩이 비율",api.formatNumber(r.ratio,4),"");}},{id:"navy-body-fat",fields:[{"key":"sex","label":"성별","type":"select","placeholder":"","default":"male","options":[["male","남성"],["female","여성"]],"raw":false},{"key":"height","label":"키 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"waist","label":"허리둘레 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"neck","label":"목둘레 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hip","label":"엉덩이둘레 (여성, cm)","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"둘레 기반 추정치이며 의료 진단이나 정밀 체성분 검사를 대신하지 않습니다.",compute:function(x){var s=String(x.sex),h=Number(x.height),w=Number(x.waist),n=Number(x.neck),hip=Number(x.hip);if(![h,w,n,hip].every(Number.isFinite)||h<=0||w<=0||n<=0||hip<0)return{error:"키·허리·목둘레는 0보다 크게 입력해 주세요."};var bf;if(s==='female'){if(hip<=0||w+hip-n<=0)return{error:"여성은 엉덩이둘레를 0보다 크게 입력해 주세요."};bf=495/(1.29579-0.35004*Math.log10(w+hip-n)+0.22100*Math.log10(h))-450;}else{if(w-n<=0)return{error:"허리둘레는 목둘레보다 커야 합니다."};bf=495/(1.0324-0.19077*Math.log10(w-n)+0.15456*Math.log10(h))-450;}return{bodyFat:bf};},format:function(r,api){return api.resultCard("추정 체지방률",api.formatNumber(r.bodyFat,2)+"%","");}},{id:"lean-body-mass",fields:[{"key":"weight","label":"체중 (kg)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bodyFat","label":"체지방률 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"입력한 체지방률의 정확도에 따라 결과가 달라집니다.",compute:function(x){var w=Number(x.weight),b=Number(x.bodyFat)/100;if(![w,b].every(Number.isFinite)||w<=0||b<0||b>=1)return{error:"체중은 0보다 크고 체지방률은 0 이상 100% 미만이어야 합니다."};return{lean:w*(1-b),fat:w*b};},format:function(r,api){return api.resultCard("제지방량",api.formatNumber(r.lean,3)+"kg","")+api.resultCard("지방량",api.formatNumber(r.fat,3)+"kg","");}},{id:"target-heart-rate-zone",fields:[{"key":"age","label":"나이","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"resting","label":"안정시 심박수 (bpm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"minIntensity","label":"최소 강도 (%)","type":"number","placeholder":"","default":"50","options":[],"raw":false},{"key":"maxIntensity","label":"최대 강도 (%)","type":"number","placeholder":"","default":"70","options":[],"raw":false}],hint:"일반적인 추정식이며 질환·약물·개인차가 있으면 전문가의 지침을 우선하세요.",compute:function(x){var a=Number(x.age),r=Number(x.resting),mi=Number(x.minIntensity)/100,ma=Number(x.maxIntensity)/100;if(!Number.isInteger(a)||a<=0||a>=220||!Number.isFinite(r)||r<=0||!Number.isFinite(mi)||!Number.isFinite(ma)||mi<0||ma<mi||ma>1)return{error:"나이·심박수와 0~100% 범위의 올바른 강도를 입력해 주세요."};var max=220-a,reserve=max-r;return{max:max,min:reserve*mi+r,maxTarget:reserve*ma+r};},format:function(r,api){return api.resultCard("목표 심박수 구간",api.formatNumber(r.min,0)+"~"+api.formatNumber(r.maxTarget,0)+" bpm","")+api.resultCard("추정 최대심박수",api.formatNumber(r.max,0)+" bpm","");}},{id:"pace-calculator",fields:[{"key":"distance","label":"거리 (km)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hours","label":"시간","type":"integer","placeholder":"","default":"0","options":[],"raw":false},{"key":"minutes","label":"분","type":"integer","placeholder":"","default":"30","options":[],"raw":false},{"key":"seconds","label":"초","type":"integer","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var d=Number(x.distance),h=Number(x.hours),m=Number(x.minutes),s=Number(x.seconds);if(![d,h,m,s].every(Number.isFinite)||d<=0||h<0||m<0||s<0)return{error:"거리는 0보다 크고 시간은 0 이상이어야 합니다."};var total=h*3600+m*60+s;if(total<=0)return{error:"소요시간은 0보다 커야 합니다."};var pace=total/d,pm=Math.floor(pace/60),ps=Math.round(pace-pm*60);if(ps===60){pm+=1;ps=0;}return{paceSeconds:pace,paceMinutes:pm,paceRemainder:ps,speed:d/(total/3600)};},format:function(r,api){var ss=String(r.paceRemainder).padStart(2,"0");return api.resultCard("1km당 페이스",r.paceMinutes+"분 "+ss+"초","")+api.resultCard("평균속도",api.formatNumber(r.speed,3)+"km/h","");}},{id:"steps-distance",fields:[{"key":"steps","label":"걸음 수","type":"integer","placeholder":"","default":"","options":[],"raw":false},{"key":"stride","label":"평균 보폭 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"보폭은 속도와 지형에 따라 달라지므로 결과는 추정치입니다.",compute:function(x){var s=Number(x.steps),l=Number(x.stride);if(!Number.isInteger(s)||s<0||!Number.isFinite(l)||l<=0)return{error:"걸음 수는 0 이상의 정수, 보폭은 0보다 크게 입력해 주세요."};var km=s*l/100000;return{km:km,meters:km*1000};},format:function(r,api){return api.resultCard("추정 이동거리",api.formatNumber(r.km,4)+"km","")+api.resultCard("미터 환산",api.formatNumber(r.meters,1)+"m","");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
